from crewai import Agent, Task

class LoopProtectedAgent(Agent):
    def __init__(self, *args, max_delegations=2, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_count = 0
        self.max_delegations = max_delegations

    def can_delegate(self, task):
        if self.delegation_count >= self.max_delegations:
            print(f'{self.name} blocked from delegating (limit reached)')
            return False
        self.delegation_count += 1
        return True

def tool_output_guard(tool_call_result):
    if not tool_call_result or 'error' in str(tool_call_result).lower():
        return {
            'validated': False,
            'fallback': 'Tool call failed - using cached/reliable data',
            'original_error': str(tool_call_result)
        }
    return {'validated': True, 'data': tool_call_result}

