from crewai import Task

class AlignedTask(Task):
    def __init__(self, *args, original_objective=None, **kwargs):
        super().__init__(*args, **kwargs)
        self.original_objective = original_objective

    def execute(self, context=None):
        if self.original_objective:
            self.description = f"{self.original_objective}\n\nCurrent task: {self.description}"
        return super().execute(context)

